INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('0feebb9e-7f45-4128-a54b-5d8d078d7694', '10078594-2707-4c3f-a212-42add04fbd84', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 30, 30, '#F59E0B', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Strong foundational understanding demonstrated. Technical decisions are correctly motivated by established engineering principles."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Solid understanding of core principles. Most decisions are correct; minor misconceptions or gaps present."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Basic understanding evident but key concepts are applied incorrectly or incompletely."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Fundamental misunderstandings of core technical concepts. Design has critical flaws."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('499fa39c-6170-4adb-a41b-18f3f16b2aff', '10078594-2707-4c3f-a212-42add04fbd84', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Communication', 'Written', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Report follows a clear and logical structure. All required sections are present and complete. References are correctly cited and consistent."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Report structure is mostly correct. Required sections present with minor omissions. References mostly consistent."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Report structure is partially correct. Some required sections are missing or incomplete. Inconsistent referencing."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Report structure is poor or largely non-conforming. Major sections missing. No or incorrect referencing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('649147ea-84e0-46dc-ad4d-18d33ed8d7ff', '10078594-2707-4c3f-a212-42add04fbd84', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Communication', 'Oral', 30, 30, '#3B82F6', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Presentation demonstrates clear understanding of project goals and outcomes. Team members field questions from all areas competently."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Presentation is competent. Most sections are clear. Team answers most questions correctly with minor gaps."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Presentation covers main points but lacks clarity in some areas. Q&A reveals knowledge gaps in certain sections."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Presentation is unclear or incomplete. Significant gaps in understanding revealed during Q&A."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('2c2eb619-5709-41d6-a377-8d3b963a6ea3', '10078594-2707-4c3f-a212-42add04fbd84', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"Exceptional collaboration. All members demonstrate technical ownership of their parts."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Solid team coordination. Most members can answer questions about all parts of the project."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Team dynamics are uneven. Some members cannot answer questions outside their area."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Poor collaboration. Major knowledge gaps across team. Lack of professional conduct."}]', 4) ON CONFLICT DO NOTHING;
