INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('53700e90-0bef-4410-aa0f-3995053ad8a2', '0e963024-a53f-4722-a9e0-5db7a47b4419', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Problem Scoping', 'Prob Scope', 25, 25, '#8B5CF6', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Problem is rigorously scoped with clear constraints, stakeholder analysis, and measurable success criteria. Literature review is thorough and relevant."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Problem scope is well-defined. Constraints and success criteria are identified. Literature review is mostly complete."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Problem is described but scoping is incomplete. Some constraints or success criteria are missing. Limited literature review."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Problem is poorly or ambiguously defined. Constraints and success criteria are absent. No meaningful literature review."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('7e8b2e8b-4a9a-4d2c-a87b-955d58d51b03', '0e963024-a53f-4722-a9e0-5db7a47b4419', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Design Innovation', 'Design', 30, 30, '#F59E0B', '[{"level":"Excellent","min":26,"max":30,"range":"26–30","desc":"Design demonstrates innovation and creative problem-solving. Novel approach is well-justified and feasible. Design documentation is exemplary."},{"level":"Good","min":20,"max":25,"range":"20–25","desc":"Design shows creative thinking with sound justification. Mostly innovative with good documentation."},{"level":"Developing","min":12,"max":19,"range":"12–19","desc":"Design is adequate but conventional. Limited creative exploration of alternatives."},{"level":"Insufficient","min":0,"max":11,"range":"0–11","desc":"Design is unoriginal and poorly justified. Little evidence of design exploration."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('5bab7e88-65ad-43a7-a14f-8b9bbcb9c9af', '0e963024-a53f-4722-a9e0-5db7a47b4419', 'c2a960c2-ec12-409c-a49b-14ac9f66a451', 'implementation_quality', 'Prototype & Testing', 'Prototype', 15, 15, '#22C55E', '[{"level":"Excellent","min":13,"max":15,"range":"13–15","desc":"Prototype is complete and demonstrates all key concepts. Tests confirm expected behaviour. Clear documentation of implementation decisions."},{"level":"Good","min":10,"max":12,"range":"10–12","desc":"Prototype demonstrates most key concepts. Most tests pass. Documentation adequate."},{"level":"Developing","min":6,"max":9,"range":"6–9","desc":"Prototype demonstrates some concepts but is incomplete. Testing is limited."},{"level":"Insufficient","min":0,"max":5,"range":"0–5","desc":"Prototype is largely non-functional or demonstrates very few concepts."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('770df56c-9bc9-4108-a5a9-1056b29af922', '0e963024-a53f-4722-a9e0-5db7a47b4419', 'cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'communication', 'Communication', 'Comm', 20, 20, '#3B82F6', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Communication is clear, professional, and well-structured. All technical and non-technical audiences are served effectively. Documentation is complete."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Communication is mostly clear. Minor gaps in clarity or audience adaptation. Documentation mostly complete."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Communication is understandable but inconsistent. Some sections unclear. Documentation incomplete."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Communication is poor or unclear. Audience needs are not served. Documentation substantially incomplete."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('36146a5d-35be-44c7-af15-a3d586386a27', '0e963024-a53f-4722-a9e0-5db7a47b4419', 'a0ce2f65-e11f-427c-ab49-6806b15b6ffe', 'teamwork', 'Teamwork', 'Team', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"Exceptional collaboration. All members demonstrate technical ownership of their parts."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Solid team coordination. Most members can answer questions about all parts of the project."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Team dynamics are uneven. Some members cannot answer questions outside their area."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Poor collaboration. Major knowledge gaps across team. Lack of professional conduct."}]', 5) ON CONFLICT DO NOTHING;
