INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('9ec0420a-7f95-4e3f-ad37-b95948485c65', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Problem Definition', 'Problem Def', 20, 20, '#8B5CF6', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Problem is clearly defined with appropriate scope. Key constraints and requirements identified. Related work is acknowledged."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Problem definition is adequate. Most requirements identified. Some gaps in scope or related work."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Problem is described but incompletely scoped. Key requirements or constraints are missing."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Problem definition is vague or missing key elements. Requirements not identified."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('52f96a98-1ac8-4b6e-aa3c-02ab77905c16', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Solution Design', 'Sol Design', 25, 25, '#F59E0B', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Design is creative, feasible, and fully addresses all requirements. Trade-offs between alternatives are explicitly analysed. Design is well-documented."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Design addresses most requirements with clear rationale. Some alternative considered. Documentation mostly complete."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Design is presented but rationale is incomplete. Limited analysis of alternatives. Some requirements not addressed."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Design is vague, incomplete, or does not address key requirements. No alternatives considered."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('e242e868-2bb7-4869-af4b-7ad480080c56', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'c2a960c2-ec12-409c-a49b-14ac9f66a451', 'implementation_quality', 'Build & Test', 'Build & Test', 25, 25, '#22C55E', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"High-quality implementation: well-structured, fully functional, and thoroughly tested. Performance meets or exceeds requirements. Code/design is maintainable."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Solid implementation. Most functionality complete and tested. Minor quality or performance issues."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Implementation has core functionality but significant gaps in testing or quality. Some features incomplete."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Implementation is substantially incomplete. Major functionality missing or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('e6928c81-092d-4b96-ada3-5dcf9bab3962', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'communication', 'Communication', 'Comm', 20, 20, '#3B82F6', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Communication is clear, professional, and well-structured. All technical and non-technical audiences are served effectively. Documentation is complete."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Communication is mostly clear. Minor gaps in clarity or audience adaptation. Documentation mostly complete."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Communication is understandable but inconsistent. Some sections unclear. Documentation incomplete."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Communication is poor or unclear. Audience needs are not served. Documentation substantially incomplete."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('5483798a-76bd-4d78-aca0-0d51ce803849', 'f8c01197-da4a-4646-a42d-8dc74715e3bc', 'a0ce2f65-e11f-427c-ab49-6806b15b6ffe', 'teamwork', 'Team Dynamics', 'Team', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Uneven participation. Some members are passive or unprepared."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 5) ON CONFLICT DO NOTHING;
