INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('3827321e-25d3-4ec5-ab6a-d8fb8d5f65fd', 'e77bf882-fc32-461c-acab-6ee1696df0c7', '10f52721-c639-4184-a0c4-1493bd620bfd', 'preliminary_report', 'Preliminary Design Review', 'PDR', 25, 25, '#6366F1', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Report is comprehensive and well-structured. All required sections are complete. Technical rationale for design choices is clearly presented."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Report covers all required sections. Most technical rationale is provided. Minor gaps in depth or organisation."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Report covers core sections but lacks depth in technical justification. Some required elements missing."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Report is incomplete or poorly structured. Major required sections absent. Technical justification lacking."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c561d84a-3cda-4605-a33c-1ceb37ebed21', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'b58a9de4-d6c7-4143-a851-ed52ef1c7aab', 'critical_design', 'Critical Design Review', 'CDR', 30, 30, '#F59E0B', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Design is fully matured: all interfaces defined, analyses completed, and risks mitigated. Ready for manufacturing/build phase."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Design is mostly matured. Key analyses completed. Some outstanding items but controlled risks."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Design is partially matured. Some interfaces undefined. Significant analysis gaps remain."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Design is immature. Major interfaces and analyses outstanding. Not ready for build phase."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('e10f1abe-f5f6-4530-ac12-708e65ef8c8f', 'e77bf882-fc32-461c-acab-6ee1696df0c7', 'a408685a-ba52-4173-a90f-b5bcf0b39b63', 'technical_performance', 'Performance & Testing', 'Performance', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"System performs exactly as designed. All mission objectives met during testing/demonstration. Jury presentation is polished and technically deep."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"System performs well. Most mission objectives met. Minor performance shortfalls explained. Presentation is competent."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"System partially functional. Some mission objectives met. Performance shortfalls partially explained. Presentation adequate."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"System does not perform adequately. Few or no mission objectives met. Presentation is poor."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('cf788ee1-eb7f-4aad-a0f7-4b6a6fcb8164', 'e77bf882-fc32-461c-acab-6ee1696df0c7', '9048c1b4-a5f6-499e-a002-58c2d231a40b', 'team_execution', 'Execution & Safety', 'Execution', 15, 15, '#EF4444', '[{"level":"Excellent","min":13,"max":15,"range":"13–15","desc":"Team demonstrated professional execution: launch procedures followed, safety protocols adhered to, and all documentation submitted on time."},{"level":"Good","min":10,"max":12,"range":"10–12","desc":"Execution was mostly professional. Minor procedure deviations. Safety generally maintained. Most documentation on time."},{"level":"Developing","min":6,"max":9,"range":"6–9","desc":"Execution had notable issues. Some safety or procedural gaps. Some documentation late or incomplete."},{"level":"Insufficient","min":0,"max":5,"range":"0–5","desc":"Significant execution failures. Safety protocols violated or major documentation missing."}]', 4) ON CONFLICT DO NOTHING;
