INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('24809e2d-ea6f-4306-a60b-8c9b5ba230e1', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', '10f52721-c639-4184-a0c4-1493bd620bfd', 'preliminary_report', 'System Concept', 'Concept', 20, 20, '#6366F1', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Concept is clearly articulated with rationale for the chosen approach. Key system components are identified and described."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Concept is described adequately. Most key components are identified. Rationale is partially provided."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Concept is partially described. Key components are not all identified. Rationale is weak."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Concept is poorly described or very incomplete. Major components missing."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c37d84a0-f0d9-4386-a75f-6ecaff196a1d', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'b58a9de4-d6c7-4143-a851-ed52ef1c7aab', 'critical_design', 'Technical Design', 'Tech Design', 30, 30, '#F59E0B', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Design is fully matured: all interfaces defined, analyses completed, and risks mitigated. Ready for manufacturing/build phase."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Design is mostly matured. Key analyses completed. Some outstanding items but controlled risks."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Design is partially matured. Some interfaces undefined. Significant analysis gaps remain."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Design is immature. Major interfaces and analyses outstanding. Not ready for build phase."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('0c95a783-0c54-42d5-a2fe-559d093af7f5', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'a408685a-ba52-4173-a90f-b5bcf0b39b63', 'technical_performance', 'Live Performance', 'Performance', 35, 35, '#22C55E', '[{"level":"Excellent","min":31,"max":35,"range":"31–35","desc":"Outstanding live performance: all primary and secondary missions completed. System behaves robustly under actual conditions. Jury presentation demonstrates deep technical understanding."},{"level":"Good","min":24,"max":30,"range":"24–30","desc":"Strong live performance with most missions completed. System is reliable. Presentation demonstrates solid technical understanding."},{"level":"Developing","min":14,"max":23,"range":"14–23","desc":"Partial performance: primary mission attempted but secondary missions incomplete or failed. Presentation covers basics."},{"level":"Insufficient","min":0,"max":13,"range":"0–13","desc":"Live performance largely unsuccessful. Critical missions failed. Presentation is inadequate."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('d4fbf826-3d87-49d5-aa3a-acad4736d44a', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', '9048c1b4-a5f6-499e-a002-58c2d231a40b', 'team_execution', 'Safety & Execution', 'Safety', 15, 15, '#EF4444', '[{"level":"Excellent","min":13,"max":15,"range":"13–15","desc":"Team demonstrated professional execution: launch procedures followed, safety protocols adhered to, and all documentation submitted on time."},{"level":"Good","min":10,"max":12,"range":"10–12","desc":"Execution was mostly professional. Minor procedure deviations. Safety generally maintained. Most documentation on time."},{"level":"Developing","min":6,"max":9,"range":"6–9","desc":"Execution had notable issues. Some safety or procedural gaps. Some documentation late or incomplete."},{"level":"Insufficient","min":0,"max":5,"range":"0–5","desc":"Significant execution failures. Safety protocols violated or major documentation missing."}]', 4) ON CONFLICT DO NOTHING;
