INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ace7bb79-4e9e-4b7f-a049-4b2684bb67d7', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', '9153ef48-d850-40bf-a60b-985c27b85214', 'originality', 'Originality & Innovation', 'Originality', 35, 35, '#8B5CF6', '[{"level":"Excellent","min":31,"max":35,"range":"31–35","desc":"Research poses a novel question not previously addressed in the accessible literature. Approach is genuinely creative and the experimental design is original."},{"level":"Good","min":24,"max":30,"range":"24–30","desc":"Research addresses an underexplored question with a creative approach. Strong originality with minor derivative elements."},{"level":"Developing","min":14,"max":23,"range":"14–23","desc":"Research is partially original. Some elements are novel but the overall approach is largely derivative."},{"level":"Insufficient","min":0,"max":13,"range":"0–13","desc":"Research closely replicates existing work with minimal novelty. No significant original contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('3ceed4da-6045-435f-aaa5-f08cafe18240', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'ed12bef7-680e-44c5-a2c2-eafd7f911f6b', 'scientific_method', 'Scientific Rigor', 'Sci Rigor', 40, 40, '#22C55E', '[{"level":"Excellent","min":35,"max":40,"range":"35–40","desc":"Scientific methodology is rigorous: hypothesis, experimental design, controls, and analysis are all correctly implemented. Conclusions follow logically from results."},{"level":"Good","min":27,"max":34,"range":"27–34","desc":"Methodology is mostly rigorous. Most steps are correctly implemented. Minor gaps in controls or analysis."},{"level":"Developing","min":16,"max":26,"range":"16–26","desc":"Methodology is described but has significant gaps. Some steps are incorrect or missing. Conclusions partially supported."},{"level":"Insufficient","min":0,"max":15,"range":"0–15","desc":"Methodology is poorly implemented or largely absent. Conclusions not supported by data."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('656fac7d-722f-4b52-aeb7-b36115296682', '05a1eb4a-d4cf-478b-a52d-578c3d9c22ad', 'b2079523-b082-451d-afaa-b9f1ae7e5141', 'impact_and_presentation', 'Societal Impact & Presentation', 'Impact', 25, 25, '#F59E0B', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Practical application of findings is clearly articulated. Societal, economic, or environmental benefit is well-argued with supporting evidence."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Application of findings is described with reasonable supporting argument. Impact is mostly well-articulated."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Impact is mentioned but not well-argued. Application is speculative or vaguely described."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"No meaningful discussion of practical impact or application. Findings are disconnected from real-world relevance."}]', 3) ON CONFLICT DO NOTHING;
