INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('f7160a57-742e-4428-ad3a-9ac826e3b2a4', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', '9153ef48-d850-40bf-a60b-985c27b85214', 'originality', 'Novelty & Originality', 'Novelty', 30, 30, '#8B5CF6', '[{"level":"Excellent","min":26,"max":30,"range":"26–30","desc":"Clear novel contribution to the field. Hypothesis is creative and not a replication of prior work. The research framing demonstrates independent thinking."},{"level":"Good","min":20,"max":25,"range":"20–25","desc":"Mostly original research framing. Some novel elements with minor overlap with existing work."},{"level":"Developing","min":12,"max":19,"range":"12–19","desc":"Research has partial novelty but significant portions are derivative or replicative."},{"level":"Insufficient","min":0,"max":11,"range":"0–11","desc":"Research is largely a replication or literature review. No significant original contribution identified."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c1ab6f6b-5e43-4f4f-aa87-bc0e498e5bf3', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'ed12bef7-680e-44c5-a2c2-eafd7f911f6b', 'scientific_method', 'Scientific Methodology', 'Methodology', 45, 45, '#22C55E', '[{"level":"Excellent","min":39,"max":45,"range":"39–45","desc":"Exceptional scientific rigour: experimental design eliminates confounds, statistical analysis is appropriate and correctly applied, and conclusions are strongly supported."},{"level":"Good","min":30,"max":38,"range":"30–38","desc":"Strong scientific rigour. Appropriate methods used with mostly correct application. Conclusions well-supported."},{"level":"Developing","min":18,"max":29,"range":"18–29","desc":"Methodology is mostly correct but has notable gaps in rigour or statistical analysis. Conclusions are partially supported."},{"level":"Insufficient","min":0,"max":17,"range":"0–17","desc":"Scientific methodology has critical flaws. Results are unreliable. Conclusions are not supported."}]', 2) ON CONFLICT DO NOTHING;
