INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('f9fff257-dd3c-402c-a751-be4cd5b12e92', '318124ea-8614-4355-ad48-2486524dfc13', '87559029-8bad-47de-afc6-43faaa45230b', 'creativity', 'Innovation & Originality', 'Innovation', 25, 25, '#8B5CF6', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Original and innovative antenna design. The approach addresses the contest challenge in an unexpected but well-justified way."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Mostly original design with clear innovative intent. Some conventional elements with good justification."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Design shows limited innovation. Approach is mostly conventional with minor novel elements."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Design is entirely conventional. No evidence of creative exploration."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('e64b33e7-ae8d-4c65-a011-618a8d31e2c4', '318124ea-8614-4355-ad48-2486524dfc13', 'ee91d9af-bcf4-49a4-a966-cbd063bbb8f5', 'technical_merit', 'Technical Depth', 'Technical', 45, 45, '#F59E0B', '[{"level":"Excellent","min":39,"max":45,"range":"39–45","desc":"Technically outstanding: rigorous electromagnetic analysis, validated by simulation and measurement. All specifications met. Design demonstrates mastery of antenna engineering."},{"level":"Good","min":30,"max":38,"range":"30–38","desc":"Very strong technical quality. Most analyses correct and validated. Minor discrepancies between simulation and measurement."},{"level":"Developing","min":18,"max":29,"range":"18–29","desc":"Adequate technical work with notable gaps. Some analyses missing or incorrect. Partial validation of specifications."},{"level":"Insufficient","min":0,"max":17,"range":"0–17","desc":"Technical work has major errors or is substantially incomplete. Specifications not demonstrated."}]', 2) ON CONFLICT DO NOTHING;
