INSERT INTO periods (id, organization_id, framework_id, name, season, is_current, is_locked, is_visible, poster_date, snapshot_frozen_at, start_date, end_date, description, updated_at) VALUES ('b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'ff81ecf1-13ac-44b2-a331-0a207a8c7184', '8df4448a-b223-4569-a92e-4c81b669b065', '2024 Contest', 'Registration', false, true, true, DATE '2024-08-15' - integer '14', ('2024-06-01'::timestamp), DATE '2024-03-01', DATE '2024-08-31', 'IEEE AP-S Student Design Contest 2024 — expert jury evaluation of student antenna and microwave engineering designs submitted internationally.', timestamp '2024-06-01' + interval '2 days') ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ba64aea1-ea3d-4194-a943-072cecebe7da', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', '87559029-8bad-47de-afc6-43faaa45230b', 'creativity', 'Creative Design', 'Creativity', 35, 35, '#8B5CF6', '[{"level":"Excellent","min":31,"max":35,"range":"31–35","desc":"Exceptionally creative design that challenges conventional approaches. Multiple innovative features are present, each well-justified. Design stands out in originality."},{"level":"Good","min":24,"max":30,"range":"24–30","desc":"Highly creative design with multiple novel features. Most are well-justified."},{"level":"Developing","min":14,"max":23,"range":"14–23","desc":"Design contains some creative elements but significant portions are conventional. Innovation is partially justified."},{"level":"Insufficient","min":0,"max":13,"range":"0–13","desc":"Design is largely conventional with at most superficial creative features."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('98470b72-67ab-4567-a032-60878aa519ac', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', 'ee91d9af-bcf4-49a4-a966-cbd063bbb8f5', 'technical_merit', 'Technical Excellence', 'Technical', 35, 35, '#F59E0B', '[{"level":"Excellent","min":30,"max":35,"range":"30–35","desc":"Technically sound design with correct analysis and good agreement between simulation and measured results. Specifications met with margin."},{"level":"Good","min":23,"max":29,"range":"23–29","desc":"Good technical quality. Analysis mostly correct. Reasonable agreement between simulation and measurement."},{"level":"Developing","min":13,"max":22,"range":"13–22","desc":"Adequate technical work but with notable errors or gaps. Partial specification compliance."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Technical work has significant errors. Specifications not met."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('4ed2d550-6e1d-445e-a788-36a46c491f1a', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', '03cdba6e-ce74-412d-ab8a-8819efca56ba', 'application_and_presentation', 'Antenna Application', 'Application', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Application is clearly identified and well-motivated. The antenna design is directly suited to the proposed use case. Real-world deployment considerations are addressed."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Application is identified with reasonable motivation. Design is mostly suited to the use case. Some deployment considerations addressed."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Application is mentioned but not well-motivated. Design suitability for the use case is only partially demonstrated."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"No clear application identified, or the design is not suited to the stated application."}]', 3) ON CONFLICT DO NOTHING;
