INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('2d275ae4-9bda-42d7-a98b-0c5c22a7346f', '10abd4e8-0cb9-4853-a17c-ac40da311bff', '4f8cf9da-b0c7-4a62-ae00-c127f9c6eb8a', 'design_compliance', 'Requirements Compliance', 'Compliance', 15, 15, '#6366F1', '[{"level":"Excellent","min":13,"max":15,"range":"13–15","desc":"Full compliance with all requirements. Documentation is complete and verifiable against the specification checklist."},{"level":"Good","min":10,"max":12,"range":"10–12","desc":"Compliance with most requirements. Minor gaps documented. Documentation mostly complete."},{"level":"Developing","min":6,"max":9,"range":"6–9","desc":"Partial compliance. Some requirements not met or not documented. Gaps not fully explained."},{"level":"Insufficient","min":0,"max":5,"range":"0–5","desc":"Significant non-compliance with requirements. Documentation is substantially incomplete."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('b5706a3d-f4c5-46a9-a86c-4b4e3082665c', '10abd4e8-0cb9-4853-a17c-ac40da311bff', '2acdc2ab-1710-48df-a764-c1e4b5e8ec4e', 'mission_execution', 'Mission Success', 'Mission', 40, 40, '#22C55E', '[{"level":"Excellent","min":35,"max":40,"range":"35–40","desc":"Mission executed successfully with all primary objectives met. System demonstrates robustness throughout. All telemetry received and within expected parameters."},{"level":"Good","min":27,"max":34,"range":"27–34","desc":"Mission largely successful. Most primary objectives met. Minor anomalies documented. Telemetry mostly within parameters."},{"level":"Developing","min":16,"max":26,"range":"16–26","desc":"Partial mission success. Some primary objectives met. Notable anomalies. Telemetry gaps present."},{"level":"Insufficient","min":0,"max":15,"range":"0–15","desc":"Mission largely unsuccessful. Critical objectives not met. Significant telemetry loss."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('73155527-14c8-4fff-a5a3-8847cbf901cc', '10abd4e8-0cb9-4853-a17c-ac40da311bff', '7065e7e2-dffe-49f3-a6bf-2d59c6661b90', 'data_and_documentation', 'Telemetry & Analysis', 'Data', 25, 25, '#F59E0B', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Data quality is high: sensors are calibrated, acquisition rate is appropriate, and all required telemetry channels are present. Data analysis is thorough and conclusions well-supported."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Good data quality. Most sensors calibrated and data acquisition complete. Analysis is mostly thorough."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Data quality is variable. Some sensors uncalibrated or channels missing. Analysis is partial."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Data quality is poor. Significant missing or corrupted channels. Analysis is absent or superficial."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('93da0efc-1f68-4c82-afa8-15b5afd72df7', '10abd4e8-0cb9-4853-a17c-ac40da311bff', '089917fe-ade5-4d49-a70d-d9b1f8f6d319', 'safety_and_recovery', 'Safety Protocol', 'Safety', 20, 20, '#EF4444', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"All safety requirements documented and implemented. Emergency procedures are complete and rehearsed. Risk register is current."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Most safety requirements implemented. Emergency procedures mostly complete. Risk register mostly current."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Some safety requirements implemented. Emergency procedures incomplete. Risk register has gaps."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Safety requirements largely unaddressed. Emergency procedures absent or inadequate."}]', 4) ON CONFLICT DO NOTHING;
