INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('93fcb76b-9827-4720-a1a8-9d65fdbc3055', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'FPGA-Based Real-Time Signal Processing for 5G NR', 1, '[{"name":"Ahmet Yılmaz","order":1},{"name":"Ahmet Kaya","order":2},{"name":"Ahmet Demir","order":3},{"name":"Ahmet Çelik","order":4}]', 'Prof. Turgut Ercan', 'TEDU EE', 'Implements a 5G NR physical-layer baseband chain on a Xilinx FPGA, covering OFDM modulation, channel estimation, and LDPC decoding for sub-6 GHz bands with under 1 ms processing latency.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46123b99-4f0a-4d61-a870-6ef0f78e371f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Low-Power IoT Sensor Network for Smart Agriculture', 2, '[{"name":"Ahmet Şahin","order":1},{"name":"Ahmet Doğan","order":2},{"name":"Ahmet Kılıç","order":3},{"name":"Ahmet Aslan","order":4}]', 'Dr. Ece Aydoğan', 'TEDU EE', 'Deploys a LoRa-based mesh sensor network monitoring soil moisture, temperature, and nutrient levels across agricultural plots, targeting 5-year coin-cell battery life with a cloud dashboard.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('733f9e70-8f7b-47dc-ad72-a604c760696f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Autonomous Drone Navigation with LiDAR SLAM', 3, '[{"name":"Ahmet Özdemir","order":1},{"name":"Ahmet Yıldız","order":2},{"name":"Ahmet Koç","order":3},{"name":"Ahmet Kaplan","order":4}]', 'Prof. Cengiz Yalın', 'TEDU EE', 'Develops an onboard perception and planning stack for indoor UAVs using 3D LiDAR point-cloud SLAM and model-predictive trajectory control for collision-free navigation.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('339948a9-b977-4c51-a1bd-c3dab5e32936', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'GaN Power Amplifier Design for Sub-6 GHz 5G', 4, '[{"name":"Ahmet Aydın","order":1},{"name":"Ahmet Güneş","order":2},{"name":"Ahmet Türk","order":3}]', 'Dr. Aylin Seçkin', 'TEDU EE', 'Designs and characterizes a GaN HEMT power amplifier achieving over 45% power-added efficiency at 3.5 GHz with digital pre-distortion linearization for 5G base-station applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('2c01817f-5c28-4899-ab4b-fb741b5f8f9b', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Edge AI Accelerator on RISC-V for Anomaly Detection', 5, '[{"name":"Ahmet Keskin","order":1},{"name":"Ahmet Uslu","order":2},{"name":"Ahmet Bulut","order":3}]', 'Prof. Tarık Özmen', 'TEDU EE', 'Implements a custom RISC-V core extended with a neural-network inference accelerator targeting sub-mW operation for real-time anomaly detection in industrial IoT edge nodes.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('bdb8459f-49ce-405e-af0f-d35e36fcdcf2', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Reconfigurable Intelligent Surface for Indoor mmWave', 6, '[{"name":"Ahmet Öztürk","order":1},{"name":"Ahmet Korkmaz","order":2},{"name":"Ahmet Çetin","order":3},{"name":"Ahmet Bozkurt","order":4}]', 'Dr. Derya Civan', 'TEDU EE', 'Prototypes a 32-element 1-bit RIS panel with programmable phase shifters to improve mmWave signal coverage in non-line-of-sight indoor environments.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('1449ba13-0409-4bd3-abc9-ddf7040c5b76', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Solar MPPT Controller with Machine Learning Optimization', 7, '[{"name":"Ahmet Demirci","order":1},{"name":"Ahmet Polat","order":2},{"name":"Ahmet Güler","order":3},{"name":"Ahmet Kurt","order":4}]', 'Prof. Hakan Tekin', 'TEDU EE', 'Applies reinforcement learning to maximum-power-point tracking on a photovoltaic system, outperforming classical P&O and incremental-conductance algorithms under partial-shading conditions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9faaa31c-cdf6-4678-a123-2bfe194ce989', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Bioimpedance Spectroscopy System for Tissue Analysis', 8, '[{"name":"Ahmet Avcı","order":1},{"name":"Ahmet Aksoy","order":2},{"name":"Ahmet Erdem","order":3},{"name":"Ahmet Şimşek","order":4}]', 'Dr. Zeliha Taşçı', 'TEDU EE', 'Builds a portable four-electrode bio-impedance spectroscopy instrument spanning 1 kHz to 1 MHz for non-invasive body-composition measurement and tissue-characterization applications.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('023ddedd-e060-4194-a7c5-8d3d27e6c3f6', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Visible Light Communication Transceiver Prototype', 9, '[{"name":"Ahmet Tekin","order":1},{"name":"Ahmet Duran","order":2},{"name":"Ahmet Ateş","order":3}]', 'Prof. Turgut Ercan', 'TEDU EE', 'Demonstrates a VLC link using off-the-shelf LEDs and photodetectors with OFDM modulation, achieving 10 Mbps throughput over a 1-meter line-of-sight channel.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('8fb336c1-ae87-45fc-a587-53fb3052016f', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'Multi-Robot Coordination via Distributed Consensus', 10, '[{"name":"Ahmet Yücel","order":1},{"name":"Ahmet Boz","order":2},{"name":"Ahmet Çalışkan","order":3},{"name":"Ahmet Peker","order":4}]', 'Dr. Ece Aydoğan', 'TEDU EE', 'Designs and validates distributed consensus algorithms enabling a fleet of differential-drive robots to autonomously form and maintain geometric formations without a central controller.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('00f25636-269c-4d25-abd5-3cdbc12a31f8', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', '6-DoF Bin-Picking Robot with Depth-Aware Object Detection', 1, '[{"name":"Ahmet Kara","order":1},{"name":"Ahmet Gündüz","order":2},{"name":"Ahmet Soylu","order":3},{"name":"Ahmet Turan","order":4}]', 'Prof. Beren Yücel', 'TEDU-EE', 'Designs a bin-picking system combining a depth camera and YOLOv8-based 6-DoF pose estimator with a UR5 arm controller; achieves 94% pick success rate on mixed-geometry industrial parts under unstructured bin conditions.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('46c52db6-2cd0-404d-a2bf-23d390c741ad', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'TinyML Keyword Spotter for Low-Power Voice-Controlled Appliances', 2, '[{"name":"Ahmet Çakır","order":1},{"name":"Ahmet Erdoğan","order":2},{"name":"Ahmet Arıcan","order":3}]', 'Prof. Gizem Aksoy', 'TEDU-EE', 'Implements quantized neural-network models on ARM Cortex-M4 microcontrollers for on-device keyword spotting and vibration-anomaly detection, achieving sub-mW inference with no cloud dependency using MCUNet-style architecture.') ON CONFLICT DO NOTHING;
