INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('4edc653f-c0e7-4217-aca1-1c827f8204aa', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'GNSS-Yoksun Ortamda Görsel-Atalet Odometrisi ile İHA Sürüsü Navigasyonu', 1, '[{"name":"Mehmet Çetin","order":1},{"name":"Mehmet Bozkurt","order":2},{"name":"Mehmet Demirci","order":3}]', 'Prof. Ezgi Doruk', 'TEKNOFEST', 'Sehir ici GNSS karistirma senaryolarinda 4 adet quadrotordan olusan bir suruyu yonlendirmek icin gorsel-atalet odometrisi tabanli dagitik bir navigasyon cercevesi gelistirilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('fd4bc2a1-e69b-4bf2-aab4-5f2da12927de', 'bf4ee98f-1fd2-418d-a62d-8cb5b585f293', 'Yüksek Özgül İtki için Oksitleyici Zenginleştirmeli Hibrit Roket Motoru', 2, '[{"name":"Mehmet Polat","order":1},{"name":"Mehmet Güler","order":2},{"name":"Mehmet Kurt","order":3},{"name":"Mehmet Avcı","order":4}]', 'Prof. Tuğçe Can', 'TEKNOFEST', 'Oksijen degistirici bir enjektur ve bolgelendirilmis yanma odasi tasarimiyla daha zengin oksitleyici-yakit orani kullanilarak yuksek ozgul itis elde eden deneysel bir hibrit roket motoru gelistirilmistir.') ON CONFLICT DO NOTHING;
