INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('a426a611-7b78-434d-a881-aa71b5849acb', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'Uydu Görüntülerinde Derin Öğrenme ile Yangın Riski Haritalaması', 1, '[{"name":"Mehmet Doruk","order":1},{"name":"Mehmet Ünal","order":2},{"name":"Mehmet Keçeci","order":3}]', 'Prof. Caner Turgut', 'TUBITAK-2204A', 'Sentinel-2 coklu-spektral uydu goruntuleri uzerinde egitilmis bir U-Net siniflandirici kullanilarak haftalik yangin riski haritalari uretilmekte ve orman yangini tehlike seviyesi geleneksel FFMC endekslerinden 23% daha erken tespit edilmektedir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('399c8138-c254-4cc4-a305-be9db396f5be', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'Endüstriyel Atıksudan Ağır Metal Giderimi için Biosorpsiyon Optimizasyonu', 2, '[{"name":"Mehmet Işık","order":1},{"name":"Mehmet Eren","order":2},{"name":"Mehmet Kayalı","order":3}]', 'Prof. Hakan Kurt', 'TUBITAK-2204A', 'Tekstil ve galvaniz atiksuyu aritma icin fistik kabugu bazli bir biyosorbent optimize edilmis; 200 mg/L baslangic konsantrasyonunda bakir ve kursun icin 95% uzeri giderim verimi elde edilmistir.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f70484ca-9482-441b-a0f1-a51bd61a5693', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', 'IMU Tabanlı Giyilebilir Boyun Duruşu İzleme ve Düzeltme Sistemi', 3, '[{"name":"Mehmet Taşkın","order":1},{"name":"Mehmet Boztepe","order":2},{"name":"Mehmet Aktaş","order":3}]', 'Prof. Damla Kılıç', 'TUBITAK-2204A', 'Boyun posturunu gercek zamanli olarak takip eden ve suregen yanlis postur sirasinda titresimli uyari veren 6-eksenli IMU tabanli bir boyun bandi gelistirilmis; on saatlik ofis calismasinda boyun agrisi vakasi 40% azalmistir.') ON CONFLICT DO NOTHING;
