INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('7c08441a-9b1c-43b1-ab4b-a6d204c8f90d', '6c44b363-4522-4cad-a251-06484b72b164', 'Phased Array Antenna for mmWave 5G (Team A)', 1, '[{"name":"James Torres","order":1},{"name":"James Peterson","order":2},{"name":"James Gray","order":3},{"name":"James Ramirez","order":4}]', 'Prof. Isaac Perez', 'IEEE-APSSDC', 'Designs a 16-element phased array antenna with integrated MMIC beamforming IC for 28 GHz 5G applications, demonstrating plus-or-minus 60 degree beam steering and 24 dBi gain.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('ca11e01d-82af-4055-aa03-4640780aa91b', '6c44b363-4522-4cad-a251-06484b72b164', 'Wearable RFID Tag Antenna for Healthcare (Team B)', 2, '[{"name":"James James","order":1},{"name":"James Watson","order":2},{"name":"James Brooks","order":3},{"name":"James Kelly","order":4}]', 'Prof. Ethan Ward', 'IEEE-APSSDC', 'Develops a conformal RFID tag antenna for the 900 MHz UHF band, optimized for on-body performance in healthcare settings with over 3 m read range despite proximity to skin.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('f587f2b0-2c8e-40bc-ac05-182f1d07cf58', '6c44b363-4522-4cad-a251-06484b72b164', 'Dual-Band Microstrip Patch Antenna (Team C)', 3, '[{"name":"James Sanders","order":1},{"name":"James Price","order":2},{"name":"James Bennett","order":3},{"name":"James Wood","order":4}]', 'Prof. Owen Gray', 'IEEE-APSSDC', 'Designs a dual-band microstrip patch antenna resonating at 2.4 GHz and 5.8 GHz for Wi-Fi applications, achieving over 6 dBi gain on both bands with a compact footprint.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('32f1ec66-89dc-49f5-a867-7ec816ff6d07', '6c44b363-4522-4cad-a251-06484b72b164', 'Metamaterial-based Radar Cross Section Reduction (Team D)', 4, '[{"name":"James Barnes","order":1},{"name":"James Ross","order":2},{"name":"James Henderson","order":3},{"name":"James Coleman","order":4}]', 'Prof. Aria Sanders', 'IEEE-APSSDC', 'Applies mushroom-type electromagnetic band-gap metamaterial structures to reduce the radar cross section of a flat metallic target by over 15 dB across the X-band (8-12 GHz).') ON CONFLICT DO NOTHING;
