INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e970c78e-aaff-43ef-a236-77caf54b07ce', '318124ea-8614-4355-ad48-2486524dfc13', 'On-Body 2.4 GHz Patch Antenna for Implant-to-Wearable BAN Link (Team B)', 2, '[{"name":"James Patterson","order":1},{"name":"James Hughes","order":2},{"name":"James Flores","order":3}]', 'Prof. Ella Brooks', 'IEEE-APSSDC', 'Characterises a flexible substrate patch antenna designed for the 2.4 GHz ISM band in body-area network scenarios, measuring path loss and SAR distribution across five tissue-equivalent phantom torso configurations.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('9c450cf6-cae4-4390-a3ed-12f231962d02', '318124ea-8614-4355-ad48-2486524dfc13', 'Wideband Yagi-Uda Array for UHF TV White-Space Cognitive Radio (Team C)', 3, '[{"name":"James Washington","order":1},{"name":"James Butler","order":2},{"name":"James Simmons","order":3}]', 'Prof. Nolan Davies', 'IEEE-APSSDC', 'Designs a compact 3-element Yagi-Uda array covering 470-790 MHz UHF TV white-space bands, demonstrating 8 dBd gain with a reconfigurable matching network enabling cognitive radio spectrum sensing across sub-bands.') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('55964658-c936-45e8-ae7c-bccdb9dcfb20', 'b7014c23-db5e-4be5-a5d6-d9597e8578cc', '60 GHz Millimetre-Wave Slot Array Antenna for Short-Range P2P Links (Team A)', 1, '[{"name":"James Foster","order":1},{"name":"James Gonzales","order":2},{"name":"James Bryant","order":3}]', 'Prof. Sophie Clarke', 'IEEE-APSSDC', 'Designs an 8x1 slot array antenna resonating at 60 GHz for IEEE 802.11ad point-to-point links, achieving 18 dBi gain and 3-dB beamwidth of 12 degrees with a low-cost Rogers substrate and SMA end-launch connector.') ON CONFLICT DO NOTHING;
