INSERT INTO projects (id, period_id, title, project_no, members, advisor_name, advisor_affiliation, description) VALUES ('e3603c93-8069-4824-afa0-10fe733475e3', '47979751-163d-48b3-ae56-a65586d18f1b', 'Atmospheric Sensor Suite Deployment - Entry 3', 3, '[{"name":"James Wallace","order":1},{"name":"James Woods","order":2},{"name":"James Cole","order":3}]', 'Prof. Mia Howard', 'CANSAT-2025', 'Integrates a miniaturized atmospheric sensor suite measuring temperature, humidity, CO2, and particulate matter into a CanSat form factor with in-flight data logging and post-flight visualization.') ON CONFLICT DO NOTHING;
